import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useParams } from 'react-router-dom';
import './PatientAppointments.css';

const PatientAppointments = () => {
    const { id } = useParams();
    const [patient, setPatient] = useState(null);
    const [appointments, setAppointments] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        fetchPatientAndAppointments();
    }, [id]);

    const fetchPatientAndAppointments = async () => {
        try {
            setLoading(true);
            const response = await axios.get(`http://localhost:5000/api/patients/${id}`);
            setPatient(response.data);
            setAppointments(response.data.appointments || []);
            setError(null);
        } catch (err) {
            setError('Error fetching patient appointments. Please try again.');
            console.error('Error:', err);
        } finally {
            setLoading(false);
        }
    };

    const formatDate = (dateString) => {
        const options = { year: 'numeric', month: 'long', day: 'numeric' };
        return new Date(dateString).toLocaleDateString(undefined, options);
    };

    if (loading) {
        return (
            <div className="loading">
                <h2>Loading Appointments...</h2>
                <p>Please wait while we fetch the appointments.</p>
            </div>
        );
    }

    if (error) {
        return (
            <div className="error">
                <h2>Error</h2>
                <p>{error}</p>
                <button onClick={fetchPatientAndAppointments} className="retry-btn">
                    Try Again
                </button>
            </div>
        );
    }

    if (!patient) {
        return (
            <div className="error">
                <h2>Error</h2>
                <p>Patient not found.</p>
            </div>
        );
    }

    return (
        <div className="patient-appointments">
            <div className="patient-info">
                <h2>Appointments for {patient.name}</h2>
                <div className="patient-details">
                    <p><strong>Email:</strong> {patient.email}</p>
                    <p><strong>Phone:</strong> {patient.phone}</p>
                    <p><strong>Age:</strong> {patient.age}</p>
                    <p><strong>Gender:</strong> {patient.gender}</p>
                </div>
            </div>

            {appointments.length === 0 ? (
                <div className="no-appointments">
                    <h3>No Appointments Found</h3>
                    <p>This patient has no appointments scheduled.</p>
                </div>
            ) : (
                <div className="appointments-grid">
                    {appointments.map((appointment) => (
                        <div key={appointment._id} className="appointment-card">
                            <div className="appointment-header">
                                <h3>Appointment Details</h3>
                                <span className={`status-badge ${appointment.status}`}>
                                    {appointment.status}
                                </span>
                            </div>

                            <div className="appointment-details">
                                <div className="detail-group">
                                    <h4>Doctor Information</h4>
                                    <p><strong>Name:</strong> Dr. {appointment.doctor?.name || 'Not assigned'}</p>
                                    <p><strong>Specialization:</strong> {appointment.doctor?.specialization || 'N/A'}</p>
                                    <p><strong>Consultation Fee:</strong> ${appointment.doctor?.consultationFee || 'N/A'}</p>
                                </div>

                                <div className="detail-group">
                                    <h4>Appointment Information</h4>
                                    <p><strong>Date:</strong> {formatDate(appointment.appointmentDate)}</p>
                                    <p><strong>Time:</strong> {appointment.appointmentTime}</p>
                                    <p><strong>Symptoms:</strong> {appointment.symptoms}</p>
                                    {appointment.notes && (
                                        <p><strong>Notes:</strong> {appointment.notes}</p>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

export default PatientAppointments;
